1	import { _decorator, Component, Node, Label, tween, v3, warn, error, EventKeyboard, Input, input, KeyCode, log } from 'cc';
2	import { DEV, DEBUG } from 'cc/env';
3	import GameView from '../GameView';
4	import { eventManager } from 'db://astarte-framework/Managers';
5	import { SpriteChange } from '../Common/SpriteChange';
6	import {
7	    SegmentDescriptor,
8	    SpinResult,
9	    FeatureWheelSegmentType,
10	    FEATURE_WHEEL_SEGMENT_COUNT,
11	    DEFAULT_ICON_INDEX,
12	    TypeToIconIndex,
13	    ComputeTargetAngle,
14	    NormalizeAngle,
15	    GetDefaultSegments,
16	} from './FeatureWheelTypes';
17	
18	const { ccclass, property } = _decorator;
19	
20	/**
21	 * @ch Feature Wheel 事件（獨立命名空間，與舊 MULTIPLIER_EVENT 不衝突，支援共存）
22	 */
23	export const FEATURE_WHEEL_EVENT = {
24	    /**
25	     * @ch 初始化
26	     * @param gameView 遊戲視窗
27	     */
28	    INIT: 'FEATURE_WHEEL_INIT',
29	
30	    /**
31	     * @ch 設置 12 格輪盤資料（server 給）
32	     * @param segments SegmentDescriptor[]（每格 type + 選填 value）
33	     */
34	    SET_WHEEL_DATA: 'FEATURE_WHEEL_SET_WHEEL_DATA',
35	
36	    /**
37	     * @ch 轉動並落在指定格
38	     * @param landIndex 落點格索引 (0~11)
39	     * @param callback (選填) (result: SpinResult) => void
40	     */
41	    PLAY_SPIN: 'FEATURE_WHEEL_PLAY_SPIN',
42	
43	    /**@ch 顯示 UI*/
44	    SHOW_UI: 'FEATURE_WHEEL_SHOW_UI',
45	
46	    /**@ch 隱藏 UI*/
47	    HIDE_UI: 'FEATURE_WHEEL_HIDE_UI',
48	
49	    /**
50	     * @ch 手動恢復 Idle 緩轉
51	     * PlaySpin 後輪盤停住不自動恢復；待盤面其他表演結束，由呼叫端 dispatch 此事件才繼續緩轉
52	     */
53	    RESUME_IDLE: 'FEATURE_WHEEL_RESUME_IDLE',
54	};
55	
56	/**
57	 * @ch Feature Wheel 輪盤 UI 元件
58	 * 單一職責：顯示 12 格、平時 Idle 緩轉、依 server 資料換 icon、轉動落在指定格、播落點演出、把選中功能拋給外部
59	 * 不碰盤面標記/重轉/改符號（呼叫端責任）
60	 */
61	@ccclass('FeatureWheelManager')
62	export class FeatureWheelManager extends Component {
63	    //#region 屬性
64	    /**@ch 根節點（顯示/隱藏）*/
65	    @property({ type: Node, displayName: '根節點' })
66	    private m_rootNode: Node = null;
67	
68	    /**@ch 輪盤旋轉節點（轉動的是這個，頂端指針固定不動）*/
69	    @property({ type: Node, displayName: '輪盤旋轉節點' })
70	    private m_wheelNode: Node = null;
71	
72	    /**@ch 12 格 icon 的 SpriteChange（順序對應格 0~11）*/
73	    @property({ type: [SpriteChange], displayName: '12 格 icon SpriteChange' })
74	    private m_segmentSpriteChanges: SpriteChange[] = [];
75	
76	    /**@ch 12 格乘倍數值 Label（非乘倍格留空字串；順序對應格 0~11）*/
77	    @property({ type: [Label], displayName: '12 格乘倍數值 Label' })
78	    private m_segmentValueLabels: Label[] = [];
79	
80	    /**@ch 12 格落點演出節點（高亮+scale 的目標；順序對應格 0~11）*/
81	    @property({ type: [Node], displayName: '12 格落點演出節點' })
82	    private m_segmentNodes: Node[] = [];
83	
84	    /**@ch 轉動方向：勾選=順時針，取消=逆時針（預設順時針）*/
85	    @property({ displayName: '順時針轉動' })
86	    private m_clockwise: boolean = true;
87	
88	    /**@ch Idle 緩轉一圈秒數（越大越慢；≤0 視為不緩轉）；方向跟隨「順時針轉動」*/
89	    @property({ displayName: 'Idle 一圈秒數' })
90	    private m_idleSecondsPerRev: number = 60;
91	    //#endregion 屬性
92	
93	    //#region 常數
94	    /**@ch 轉動時間（秒）；拉長以降低峰值角速度，減輕 12 格重複圖樣的車輪錯覺（視覺反向）*/
95	    private static readonly ROTATE_TIME = 2.5;
96	    /**@ch 落點演出放大倍率*/
97	    private static readonly ANNOUNCE_SCALE = 1.25;
98	    /**@ch 落點演出單段時間（秒）*/
99	    private static readonly ANNOUNCE_TIME = 0.18;
100	    //#endregion 常數
101	
102	    //#region 變數
103	    /**@ch 遊戲視窗*/
104	    private m_gameView: GameView = null;
105	    /**@ch 是否初始化*/
106	    private m_isInit = false;
107	    /**@ch 是否轉動中（轉動中/閒置兩互斥態）*/
108	    private m_isSpinning = false;
109	    /**@ch 是否處於 Idle 緩轉態（SHOW_UI/RESUME_IDLE 開、HIDE_UI/PlaySpin 關；轉動中由 m_isSpinning 暫停，轉完不自動恢復）*/
110	    private m_isIdle = false;
111	    /**@ch 是否已註冊事件*/
112	    private m_isEventRegistered = false;
113	    /**@ch 當前 12 格資料*/
114	    private m_segments: SegmentDescriptor[] = [];
115	
116	    /**@ch 事件列表*/
117	    private readonly EVENT_LIST: string[] = [
118	        FEATURE_WHEEL_EVENT.INIT,
119	        FEATURE_WHEEL_EVENT.SET_WHEEL_DATA,
120	        FEATURE_WHEEL_EVENT.PLAY_SPIN,
121	        FEATURE_WHEEL_EVENT.SHOW_UI,
122	        FEATURE_WHEEL_EVENT.HIDE_UI,
123	        FEATURE_WHEEL_EVENT.RESUME_IDLE,
124	    ];
125	    //#endregion 變數
126	
127	    //#region 生命週期
128	    onLoad() {
129	        this.RegisterEvent();
130	        this.DevAssertConfig();
131	        this.RegisterTestKeyCodes();
132	    }
133	
134	    onDestroy() {
135	        this.UnregisterEvent();
136	        this.UnregisterTestKeyCodes();
137	    }
138	
139	    /**
140	     * @ch 每幀 Idle 緩轉：僅在 Idle 態且非轉動中執行（兩旋轉路徑互斥，不同幀寫 m_wheelNode）
141	     * 方向跟隨 m_clockwise（順時針 = z 遞減，與 ComputeTargetAngle 一致）
142	     */
143	    update(dt: number) {
144	        if (!this.m_isIdle || this.m_isSpinning) {
145	            return;
146	        }
147	        if (this.m_idleSecondsPerRev <= 0) {
148	            return;
149	        }
150	        if (!this.m_wheelNode || !this.m_wheelNode.isValid) {
151	            return;
152	        }
153	        const dir = this.m_clockwise ? -1 : 1;
154	        const deltaAngle = dir * (360 / this.m_idleSecondsPerRev) * dt;
155	        // 正規化防 BC-8 連續累積漂移（與 RotateToIndex 收尾一致），spin 起點讀 currentAngle 仍正確
156	        const next = NormalizeAngle(this.m_wheelNode.eulerAngles.z + deltaAngle);
157	        this.m_wheelNode.setRotationFromEuler(0, 0, next);
158	    }
159	    //#endregion 生命週期
160	
161	    //#region 事件註冊
162	    private RegisterEvent() {
163	        if (this.m_isEventRegistered) {
164	            return;
165	        }
166	        this.m_isEventRegistered = true;
167	        this.EVENT_LIST.forEach(event => eventManager.Register(event, this));
168	    }
169	
170	    private UnregisterEvent() {
171	        if (!this.m_isEventRegistered) {
172	            return;
173	        }
174	        this.EVENT_LIST.forEach(event => eventManager.UnRegister(event, this));
175	        this.m_isEventRegistered = false;
176	    }
177	
178	    /**
179	     * @ch 事件分派
180	     */
181	    OnEvent(event: string, ...args: any[]) {
182	        switch (event) {
183	            case FEATURE_WHEEL_EVENT.INIT:
184	                if (args.length > 0 && typeof args[0] === 'object' && args[0] !== null) {
185	                    this.Init(args[0]);
186	                } else {
187	                    error('FeatureWheel INIT 參數無效');
188	                }
189	                break;
190	
191	            case FEATURE_WHEEL_EVENT.SET_WHEEL_DATA:
192	                if (args.length > 0 && Array.isArray(args[0])) {
193	                    this.SetWheelData(args[0]);
194	                } else {
195	                    error('FeatureWheel SET_WHEEL_DATA 參數無效');
196	                }
197	                break;
198	
199	            case FEATURE_WHEEL_EVENT.PLAY_SPIN:
200	                if (args.length > 0 && typeof args[0] === 'number') {
201	                    this.PlaySpin(args[0], typeof args[1] === 'function' ? args[1] : undefined);
202	                } else {
203	                    error('FeatureWheel PLAY_SPIN 參數無效');
204	                }
205	                break;
206	
207	            case FEATURE_WHEEL_EVENT.SHOW_UI:
208	                this.SetUIShow(true);
209	                break;
210	
211	            case FEATURE_WHEEL_EVENT.HIDE_UI:
212	                this.SetUIShow(false);
213	                break;
214	
215	            case FEATURE_WHEEL_EVENT.RESUME_IDLE:
216	                this.ResumeIdle();
217	                break;
218	        }
219	    }
220	    //#endregion 事件註冊
221	
222	    //#region 方法
223	    /**
224	     * @ch 初始化（IF-1）
225	     */
226	    private Init(gameView: GameView) {
227	        this.m_gameView = gameView;
228	        this.m_isInit = true;
229	    }
230	
231	    /**
232	     * @ch 設置 12 格資料並更新 icon（IF-2 / BC-5 / EH-2）
233	     * @param segments server 給的 12 格資料
234	     */
235	    private SetWheelData(segments: SegmentDescriptor[]) {
236	        // BC-9 行為約束：轉動中拒絕換資料，避免落點與顯示不一致
237	        if (this.m_isSpinning) {
238	            warn('FeatureWheel SetWheelData 轉動中，拒絕本次設置');
239	            return;
240	        }
241	        if (!segments) {
242	            warn('FeatureWheel SetWheelData 資料為空');
243	            return;
244	        }
245	
246	        // EH-2：長度 > 10 取前 10
247	        if (segments.length > FEATURE_WHEEL_SEGMENT_COUNT) {
248	            warn(`FeatureWheel SetWheelData 長度 ${segments.length} > ${FEATURE_WHEEL_SEGMENT_COUNT}，取前 ${FEATURE_WHEEL_SEGMENT_COUNT} 格`);
249	        }
250	        this.m_segments = segments.slice(0, FEATURE_WHEEL_SEGMENT_COUNT);
251	
252	        // EH-2：長度 < 10 → 渲染已提供格，其餘格保持預設
253	        if (this.m_segments.length < FEATURE_WHEEL_SEGMENT_COUNT) {
254	            warn(`FeatureWheel SetWheelData 長度 ${this.m_segments.length} < ${FEATURE_WHEEL_SEGMENT_COUNT}，其餘格保持預設`);
255	        }
256	
257	        this.BindSegmentIcons();
258	    }
259	
260	    /**
261	     * @ch 依當前資料綁定各格 icon 與乘倍數值（BC-5 / BC-4 / EH-2 未知 type）
262	     */
263	    private BindSegmentIcons() {
264	        // 迭代固定 12 格確保冪等（R-2）：二次設定變少時，超出資料的格重置為預設，不殘留舊值
265	        for (let i = 0; i < FEATURE_WHEEL_SEGMENT_COUNT; i++) {
266	            const seg = i < this.m_segments.length ? this.m_segments[i] : null;
267	
268	            // 換 icon（BC-4：未知 type 由 TypeToIconIndex 回傳預設索引；無資料格用預設）
269	            const spriteChange = this.m_segmentSpriteChanges[i];
270	            if (spriteChange) {
271	                spriteChange.ChangeSpriteByIndex(seg ? TypeToIconIndex(seg.type) : DEFAULT_ICON_INDEX);
272	            }
273	
274	            // 乘倍數值（BC-5：僅乘倍格顯示 x{value}；其餘格空字串）
275	            const label = this.m_segmentValueLabels[i];
276	            if (label) {
277	                label.string = (seg && seg.type === FeatureWheelSegmentType.Multiplier && seg.value !== undefined)
278	                    ? `x${seg.value}`
279	                    : '';
280	            }
281	        }
282	    }
283	
284	    /**
285	     * @ch 轉動並落在指定格（IF-3 / BC-3 / BC-6 / BC-7 / BC-8 / BC-9 / EH-1 / EH-3）
286	     * 守衛順序（DR-10）：① 轉動中重入 → ② 未初始化/無資料 → ③ landIndex 範圍
287	     * 完成訊號鏈（DR-2 / BC-7）：await 轉動 → await 落點演出 → callback → 最後釋放 m_isSpinning
288	     * @param landIndex 落點格索引 (0~11)
289	     * @param callback 完成回調，帶選中格 {index, type, value}
290	     */
291	    private async PlaySpin(landIndex: number, callback?: (result: SpinResult) => void) {
292	        // ① BC-9 轉動中重入 → 忽略
293	        if (this.m_isSpinning) {
294	            warn('FeatureWheel PlaySpin 轉動中，忽略本次請求');
295	            return;
296	        }
297	        // ② EH-3 未初始化或無資料
298	        if (!this.m_isInit || this.m_segments.length === 0) {
299	            warn('FeatureWheel PlaySpin 未初始化或尚未設置輪盤資料');
300	            return;
301	        }
302	        // ③ EH-1 landIndex 範圍
303	        if (landIndex < 0 || landIndex >= FEATURE_WHEEL_SEGMENT_COUNT) {
304	            warn(`FeatureWheel PlaySpin landIndex ${landIndex} 超出範圍 0~${FEATURE_WHEEL_SEGMENT_COUNT - 1}`);
305	            return;
306	        }
307	
308	        this.m_isSpinning = true;
309	        // 轉動開始即關閉 Idle：轉完「不」自動恢復；待盤面其他表演結束由 RESUME_IDLE 手動恢復
310	        this.m_isIdle = false;
311	        try {
312	            await this.RotateToIndex(landIndex);     // BC-3 / BC-6
313	            await this.PlayLandAnnounce(landIndex);  // BC-7
314	            const seg = this.m_segments[landIndex];
315	            // callback 包獨立 try（R-1）：呼叫端 callback 自身例外不被遮蔽成「轉動失敗」
316	            try {
317	                callback?.({ index: landIndex, type: seg.type, value: seg.value });
318	            } catch (cbErr) {
319	                error('FeatureWheel PlaySpin callback 執行失敗: ' + cbErr);
320	            }
321	        } catch (e) {
322	            error('FeatureWheel PlaySpin 轉動/演出失敗: ' + e);
323	        } finally {
324	            // BC-7：釋放點在 callback 之後，避免演出/回呼期間被重入
325	            this.m_isSpinning = false;
326	        }
327	    }
328	
329	    /**
330	     * @ch 旋轉到 landIndex，停在頂端指針（BC-3 / BC-6）
331	     * 角度計算用 ComputeTargetAngle（依 m_clockwise 單向單調，不沿用會反向的 angleDiff）
332	     */
333	    private RotateToIndex(landIndex: number): Promise<void> {
334	        return new Promise<void>((resolve) => {
335	            if (!this.m_wheelNode || !this.m_wheelNode.isValid) {
336	                resolve();
337	                return;
338	            }
339	            const currentAngle = this.m_wheelNode.eulerAngles.z;
340	            const targetAngle = ComputeTargetAngle(landIndex, currentAngle, this.m_clockwise);
341	            const anim = { angle: currentAngle };
342	            tween(anim)
343	                .to(FeatureWheelManager.ROTATE_TIME, { angle: targetAngle }, {
344	                    easing: 'cubicOut',
345	                    onUpdate: () => {
346	                        if (this.m_wheelNode?.isValid) {
347	                            this.m_wheelNode.setRotationFromEuler(0, 0, anim.angle);
348	                        }
349	                    },
350	                })
351	                .call(() => {
352	                    // DR-9：轉動結束後正規化角度，防 BC-8 連續轉動累積漂移
353	                    if (this.m_wheelNode?.isValid) {
354	                        this.m_wheelNode.setRotationFromEuler(0, 0, NormalizeAngle(targetAngle));
355	                    }
356	                    resolve();
357	                })
358	                .start();
359	        });
360	    }
361	
362	    /**
363	     * @ch 輕量落點演出：目標格高亮 + scale 彈一下，演出完成才 resolve（BC-7）
364	     * 預留接口：未來可在此依 type 改播專屬 Spine 演出
365	     */
366	    private PlayLandAnnounce(landIndex: number): Promise<void> {
367	        return new Promise<void>((resolve) => {
368	            const node = this.m_segmentNodes[landIndex];
369	            if (!node || !node.isValid) {
370	                resolve();
371	                return;
372	            }
373	            const s = FeatureWheelManager.ANNOUNCE_SCALE;
374	            const t = FeatureWheelManager.ANNOUNCE_TIME;
375	            tween(node)
376	                .to(t, { scale: v3(s, s, s) }, { easing: 'backOut' })
377	                .to(t, { scale: v3(1, 1, 1) }, { easing: 'backIn' })
378	                .call(() => resolve())
379	                .start();
380	        });
381	    }
382	
383	    /**
384	     * @ch 顯示/隱藏 UI（IF-4）
385	     */
386	    private SetUIShow(isShow: boolean) {
387	        if (this.m_rootNode) {
388	            this.m_rootNode.active = isShow;
389	        }
390	        // Idle：顯示時開始緩轉、隱藏時停止（PlaySpin 後不自動恢復，須由 RESUME_IDLE 手動恢復）
391	        this.m_isIdle = isShow;
392	    }
393	
394	    /**
395	     * @ch 手動恢復 Idle 緩轉（IF）
396	     * 用途：PlaySpin 後輪盤停住，呼叫端在盤面其他表演結束後觸發此方法才續轉
397	     * 注意：若仍在轉動中，由 update 的 m_isSpinning 守衛延後至轉完才實際緩轉
398	     */
399	    private ResumeIdle() {
400	        this.m_isIdle = true;
401	    }
402	
403	    /**
404	     * @ch dev-only 設定斷言（DR-3/DR-12 緩解：驗節點數量，順序語意仍須人工核對 prefab）
405	     */
406	    private DevAssertConfig() {
407	        if (!DEV) {
408	            return;
409	        }
410	        if (this.m_segmentSpriteChanges.length !== FEATURE_WHEEL_SEGMENT_COUNT) {
411	            warn(`FeatureWheel 設定異常：SpriteChange 數 ${this.m_segmentSpriteChanges.length} ≠ ${FEATURE_WHEEL_SEGMENT_COUNT}`);
412	        }
413	        if (this.m_segmentNodes.length !== FEATURE_WHEEL_SEGMENT_COUNT) {
414	            warn(`FeatureWheel 設定異常：落點節點數 ${this.m_segmentNodes.length} ≠ ${FEATURE_WHEEL_SEGMENT_COUNT}`);
415	        }
416	    }
417	    //#endregion 方法
418	
419	    //#region 測試功能
420	    /**@ch 測試用：當前轉動落點索引（每次轉動 +1 循環 0~11）*/
421	    private m_testLandIndex = 0;
422	    /**@ch 測試用：當前 UI 顯示狀態（給 DIGIT_4 切換）*/
423	    private m_testUIShown = false;
424	
425	    /**
426	     * @ch 註冊測試按鍵（僅 DEBUG 構建生效；正式構建零副作用）
427	     */
428	    private RegisterTestKeyCodes() {
429	        if (!DEBUG) {
430	            return;
431	        }
432	        input.on(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
433	    }
434	
435	    /**
436	     * @ch 取消註冊測試按鍵（與 RegisterTestKeyCodes 對稱，避免監聽洩漏）
437	     */
438	    private UnregisterTestKeyCodes() {
439	        if (!DEBUG) {
440	            return;
441	        }
442	        input.off(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
443	    }
444	
445	    /**
446	     * @ch 檢查測試按鍵，走真實 eventManager 事件路徑驗證 FeatureWheel 功能
447	     * DIGIT_1：初始化 + 設定預設輪盤資料 + 顯示 UI（一鍵就緒）
448	     * DIGIT_2：轉動到下一格（循環 0~11）並印出落點結果（驗證旋轉/落點演出/callback）
449	     * DIGIT_3：重設隨機輪盤資料（驗證 icon 與乘倍數值動態更新）
450	     * DIGIT_4：切換顯示/隱藏 UI
451	     */
452	    private CheckTestKeyCode(event: EventKeyboard) {
453	        switch (event.keyCode) {
454	            case KeyCode.DIGIT_1:
455	                log('[FeatureWheel 測試] 初始化 + 設定預設資料 + 顯示 UI');
456	                // INIT 僅需非 null 物件以通過參數驗證並翻起 m_isInit；
457	                // m_gameView 在本元件未被讀取，測試以 this.node 佔位即可
458	                eventManager.Dispatch(FEATURE_WHEEL_EVENT.INIT, this.node);
459	                eventManager.Dispatch(FEATURE_WHEEL_EVENT.SET_WHEEL_DATA, GetDefaultSegments());
460	                eventManager.Dispatch(FEATURE_WHEEL_EVENT.SHOW_UI);
461	                break;
462	
463	            case KeyCode.DIGIT_2: {
464	                const landIndex = this.m_testLandIndex % FEATURE_WHEEL_SEGMENT_COUNT;
465	                this.m_testLandIndex++;
466	                log(`[FeatureWheel 測試] 轉動到第 ${landIndex} 格`);
467	                eventManager.Dispatch(FEATURE_WHEEL_EVENT.PLAY_SPIN, landIndex, (result: SpinResult) => {
468	                    const valueText = result.value === undefined ? '-' : result.value;
469	                    log(`[FeatureWheel 測試] 落點結果 index=${result.index} type=${result.type} value=${valueText}`);
470	                });
471	                break;
472	            }
473	
474	            case KeyCode.DIGIT_3:
475	                log('[FeatureWheel 測試] 重設隨機輪盤資料');
476	                eventManager.Dispatch(FEATURE_WHEEL_EVENT.SET_WHEEL_DATA, this.BuildRandomTestSegments());
477	                break;
478	
479	            case KeyCode.DIGIT_4:
480	                this.m_testUIShown = !this.m_testUIShown;
481	                log(`[FeatureWheel 測試] 切換 UI 顯示 → ${this.m_testUIShown}`);
482	                eventManager.Dispatch(this.m_testUIShown ? FEATURE_WHEEL_EVENT.SHOW_UI : FEATURE_WHEEL_EVENT.HIDE_UI);
483	                break;
484	        }
485	    }
486	
487	    /**
488	     * @ch 產生 12 格隨機測試資料（type 隨機；Multiplier 帶隨機倍數）
489	     */
490	    private BuildRandomTestSegments(): SegmentDescriptor[] {
491	        const types = [
492	            FeatureWheelSegmentType.SymbolConvert,
493	            FeatureWheelSegmentType.Multiplier,
494	            FeatureWheelSegmentType.Upgrade,
495	            FeatureWheelSegmentType.GrandJP,
496	            FeatureWheelSegmentType.FreeGame,
497	        ];
498	        const multiplierValues = [2, 3, 5, 10, 20];
499	        const segments: SegmentDescriptor[] = [];
500	        for (let i = 0; i < FEATURE_WHEEL_SEGMENT_COUNT; i++) {
501	            const type = types[Math.floor(Math.random() * types.length)];
502	            const seg: SegmentDescriptor = { type };
503	            if (type === FeatureWheelSegmentType.Multiplier) {
504	                seg.value = multiplierValues[Math.floor(Math.random() * multiplierValues.length)];
505	            }
506	            segments.push(seg);
507	        }
508	        return segments;
509	    }
510	    //#endregion 測試功能
511	}
