 * @ch 取得輪盤資料
 * @param index 輪盤索引
 * @returns 輪盤資料
 */
GetGoldBlitzRouletteWheelData(index: number): number[]
{
    if (index < 0 || index >= this.m_goldBlitzRouletteWheelData.length) {
        return null;
    }
    return this.m_goldBlitzRouletteWheelData[index].Data;
}

/**
 * @ch 取得輪盤總回合數
 * @param freeGameWheelIndex 輪盤索引
 * @param freeGameWheelNumberIndex 輪盤數字索引
 * @returns 輪盤總回合數
 */
GetGoldBlitzRouletteTotalRound(freeGameWheelIndex: number, freeGameWheelNumberIndex: number): number
{
    const wheelData = this.GetGoldBlitzRouletteWheelData(freeGameWheelIndex);
    if (!wheelData) {
        return 0;
    }
    return wheelData[freeGameWheelNumberIndex];
}
//#endregion 一般功能

//#region 音樂音效
//音效
private LoadSound()
{
    // 載入音效混音設定檔（BGM_SFX.json），讓 AudioManager 套用每個 clip 的 volume / loop / limit
    const loadSettingJson = () =>
    {
        Define.GameBundle.load( "Sound/BGM_SFX", JsonAsset, ( err: Error | null, jsonAsset: JsonAsset ) =>
        {
            if ( err )
            {
                error( err.message || err );
                loadSettingJson();
                return;
            }
            AudioManager.SetSettingJson( jsonAsset );
        } );
    };
    loadSettingJson();

    //音效
    let load = ( path: string, cb: ( clip: AudioClip ) => void ) =>
    {
        Define.GameBundle.load( path, ( err: Error, audioClip: AudioClip ) =>
        {
            if ( err )
            {
                error( err.message || err );
                load( path, cb );
                return;
            }
            cb && cb( audioClip );

