async PlayGoldBlitzRoulette() : Promise<void>
{
    log( "PlayGoldBlitzRoulette" );

    if (!this.m_gameView.GoldBlitzRouletteWheelData || this.m_gameView.GoldBlitzRouletteWheelData.length <= 0) {
        error("[EnterFreeState] GoldBlitzRouletteWheelData is invalid");
        return;
    }

    if (!this.m_gameView.RoundInfo) {
        error("[EnterFreeState] RoundInfo is invalid");
        return;
    }

    // if (this.m_gameView.RoundInfo.FreeGameWheelIndex < 0 || this.m_gameView.RoundInfo.FreeGameWheelNumberIndex < 0) {
    //     error("[EnterFreeState] FreeGameWheelIndex or FreeGameWheelNumberIndex is invalid");
    //     return;
    // }

    // // 設定輪盤資料
    // const wheelData = this.m_gameView.GetGoldBlitzRouletteWheelData(this.m_gameView.RoundInfo.FreeGameWheelIndex);
    // const stopIndex = this.m_gameView.RoundInfo.FreeGameWheelNumberIndex;
    // eventManager.Dispatch( GOLD_BLITZ_ROULETTE_EVENT.INIT, wheelData, stopIndex, this.m_gameView.RoundInfo.FreeMultiplierIndex );

    // 初始化免費遊戲回合數字
    // eventManager.Dispatch( FREE_GAME_ROUND_UI_EVENT.INIT, 0, wheelData[stopIndex] );
    // await Define.Wait( this.m_gameView, GOLD_BLITZ_ROULETTE_INIT_DELAY_SECONDS );

    // 註冊輪盤播放完成事件
    eventManager.Register( GOLD_BLITZ_ROULETTE_EVENT.ROTATE_COMPLETE, this );
    this.m_isPlayGoldBlitzRouletteFinish = false;

    // 隱藏其他 UI
    this.SetOhterUIShow(false, GOLD_BLITZ_ROULETTE_HIDE_OTHER_UI_DELAY_SECONDS);

    // 顯示輪盤
    await this.PlayGoldBlitzRouletteInAnim();

    // 等待輪盤Spin完成
    await WaitUntil(() => this.m_isPlayGoldBlitzRouletteFinish);

    // 取消註冊輪盤播放完成事件
    eventManager.UnRegister( GOLD_BLITZ_ROULETTE_EVENT.ROTATE_COMPLETE, this );

    // 顯示其他 UI
    this.SetOhterUIShow(true, GOLD_BLITZ_ROULETTE_SHOW_OTHER_UI_DELAY_SECONDS);

    // 推入免費遊戲回合數字節點
    eventManager.Dispatch(MAGIC_POT_EVENT.PUSH_TO_FREE_GAME_NUMBER_ROOT_NODE);

    // 切換倍率UI
    eventManager.Dispatch( MULTIPLIER_EVENT.SWITCH_ROULETTE_UI, MultiplierType.FreeGame );

    // // 設置倍率
    // const multiplierIndex = this.m_gameView.RoundInfo.FreeMultiplierIndex;
    // eventManager.Dispatch(MULTIPLIER_EVENT.SET_INDEX, multiplierIndex, true);

    // 更新背景
    this.m_gameView.CheckBackground();

    // 隱藏輪盤
    await this.PlayGoldBlitzRouletteOutAnim();
}

