1	/**
2	 * @ch FeatureWheel 純邏輯層自動化測試（Phase 4）
3	 * 對象：assets/Script/FeatureWheel/FeatureWheelTypes.ts（零 cc 依賴，可在 Node 跑）
4	 * 執行：npx ts-node -O '{"module":"commonjs"}' --transpile-only tests/FeatureWheelTypes.test.ts
5	 * 涵蓋：[testable] BC-1, BC-2, BC-3, BC-4, BC-8 + 純 helper
6	 */
7	
8	import {
9	    FeatureWheelSegmentType,
10	    ParseServerWheelData,
11	    ComputeTargetAngle,
12	    TypeToIconIndex,
13	    NormalizeAngle,
14	    IsKnownSegmentType,
15	    GetDefaultSegments,
16	    FEATURE_WHEEL_SEGMENT_COUNT,
17	    FEATURE_WHEEL_SEGMENT_ANGLE,
18	    FEATURE_WHEEL_EXTRA_CIRCLES,
19	    DEFAULT_ICON_INDEX,
20	} from '../assets/Script/FeatureWheel/FeatureWheelTypes';
21	
22	let total = 0;
23	let passed = 0;
24	const failures: string[] = [];
25	
26	function check(name: string, cond: boolean): void {
27	    total++;
28	    if (cond) {
29	        passed++;
30	    } else {
31	        failures.push(name);
32	        console.log(`  ❌ ${name}`);
33	    }
34	}
35	
36	function approx(a: number, b: number, eps = 1e-9): boolean {
37	    return Math.abs(a - b) < eps;
38	}
39	
40	// ─────────────────────────────────────────────
41	// BC-1：ParseServerWheelData 對合法 raw 回 10 格，type 正確映射、乘倍帶 value
42	// ─────────────────────────────────────────────
43	{
44	    const raw = {
45	        Segments: [
46	            { Type: 0 }, { Type: 1, Value: 7 }, { Type: 2 }, { Type: 3 }, { Type: 4 },
47	            { Type: 0 }, { Type: 1, Value: 2 }, { Type: 2 }, { Type: 3 }, { Type: 4 },
48	        ],
49	    };
50	    const r = ParseServerWheelData(raw);
51	    check('BC-1 正常：回傳剛好 10 格', r.length === FEATURE_WHEEL_SEGMENT_COUNT);
52	    check('BC-1 正常：type 依序映射', r[0].type === FeatureWheelSegmentType.SymbolConvert && r[4].type === FeatureWheelSegmentType.FreeGame);
53	    check('BC-1 正常：乘倍格帶 value', r[1].type === FeatureWheelSegmentType.Multiplier && r[1].value === 7);
54	    check('BC-1 正常：非乘倍格無 value', r[0].value === undefined && r[2].value === undefined);
55	    // 邊界：乘倍格缺 Value → value 維持 undefined（不崩潰）
56	    const r2 = ParseServerWheelData({ Segments: [{ Type: 1 }, { Type: 0 }, { Type: 0 }, { Type: 0 }, { Type: 0 }, { Type: 0 }, { Type: 0 }, { Type: 0 }, { Type: 0 }, { Type: 0 }] });
57	    check('BC-1 邊界：乘倍格缺 Value → undefined', r2[0].type === FeatureWheelSegmentType.Multiplier && r2[0].value === undefined);
58	}
59	
60	// ─────────────────────────────────────────────
61	// BC-2：ParseServerWheelData fallback — 永遠回 10 格
62	// ─────────────────────────────────────────────
63	{
64	    check('BC-2 null → 10 格 fallback', ParseServerWheelData(null).length === 10);
65	    check('BC-2 undefined → 10 格', ParseServerWheelData(undefined).length === 10);
66	    check('BC-2 空物件（無 Segments）→ 10 格', ParseServerWheelData({}).length === 10);
67	    check('BC-2 Segments 非陣列 → 10 格', ParseServerWheelData({ Segments: 'x' }).length === 10);
68	    check('BC-2 空 Segments 陣列 → 10 格（全預設）', ParseServerWheelData({ Segments: [] }).length === 10);
69	
70	    // 違規/未知 type → 該格補預設（BC-2 保證 10 格）
71	    const fallback = GetDefaultSegments();
72	    const unknown = ParseServerWheelData({ Segments: [{ Type: 99 }] });
73	    check('BC-2 未知 type → 補預設且仍 10 格', unknown.length === 10 && unknown[0].type === fallback[0].type);
74	
75	    // 部分缺漏 → 前格用 server、其餘補預設
76	    const partial = ParseServerWheelData({ Segments: [{ Type: 1, Value: 9 }] });
77	    check('BC-2 部分缺漏：index0 用 server', partial[0].type === FeatureWheelSegmentType.Multiplier && partial[0].value === 9);
78	    check('BC-2 部分缺漏：其餘補預設且 10 格', partial.length === 10 && partial[5].type === fallback[5].type);
79	}
80	
81	// ─────────────────────────────────────────────
82	// BC-3：ComputeTargetAngle 單向單調 + 落點正確（順時針 / 逆時針雙向）
83	// 圈數期望引用常數 FEATURE_WHEEL_EXTRA_CIRCLES，避免硬編碼被調校打破
84	// ─────────────────────────────────────────────
85	{
86	    const C = FEATURE_WHEEL_SEGMENT_ANGLE; // 36
87	    const EXTRA = FEATURE_WHEEL_EXTRA_CIRCLES * 360; // 隨常數連動
88	
89	    // 預設（順時針）→ 遞減；逆時針 → 遞增
90	    check('BC-3 CW 預設：land0 from 0 → -EXTRA', approx(ComputeTargetAngle(0, 0), -EXTRA));
91	    check('BC-3 CCW：land0 from 0 → +EXTRA', approx(ComputeTargetAngle(0, 0, false), EXTRA));
92	    check('BC-3 CCW：land3 from 0 → 3C+EXTRA', approx(ComputeTargetAngle(3, 0, false), 3 * C + EXTRA));
93	
94	    for (let land = 0; land < 10; land++) {
95	        for (const cur of [0, 17, 100, 250, 359]) {
96	            // 順時針（預設）：遞減，落點對齊 base，位移幅度 ∈ [EXTRA, EXTRA+360)
97	            const tcw = ComputeTargetAngle(land, cur);
98	            check(`BC-3 CW 落點：land${land} cur${cur} 對齊 base`, approx(((tcw % 360) + 360) % 360, (land * C) % 360));
99	            check(`BC-3 CW 遞減：land${land} cur${cur} target<current`, tcw < cur);
100	            const dcw = cur - tcw;
101	            check(`BC-3 CW 不變號：land${land} cur${cur} |delta|∈[EXTRA,EXTRA+360)`, dcw >= EXTRA - 1e-9 && dcw < EXTRA + 360 + 1e-9);
102	
103	            // 逆時針：遞增，同落點
104	            const tccw = ComputeTargetAngle(land, cur, false);
105	            check(`BC-3 CCW 落點：land${land} cur${cur} 對齊 base`, approx(((tccw % 360) + 360) % 360, (land * C) % 360));
106	            check(`BC-3 CCW 遞增：land${land} cur${cur} target>current`, tccw > cur);
107	            const dccw = tccw - cur;
108	            check(`BC-3 CCW 不變號：land${land} cur${cur} delta∈[EXTRA,EXTRA+360)`, dccw >= EXTRA - 1e-9 && dccw < EXTRA + 360 + 1e-9);
109	        }
110	    }
111	}
112	
113	// ─────────────────────────────────────────────
114	// BC-8：連續多次轉動 — 每次同向單調、落點正確、正規化防漂移（雙向）
115	// ─────────────────────────────────────────────
116	{
117	    const C = FEATURE_WHEEL_SEGMENT_ANGLE;
118	    const lands = [3, 7, 0, 9, 5, 5]; // 含重複落點（5→5）
119	
120	    for (const clockwise of [true, false]) {
121	        let cur = 0;
122	        let allMono = true;
123	        let allLand = true;
124	        let allBounded = true;
125	        for (const land of lands) {
126	            const t = ComputeTargetAngle(land, cur, clockwise);
127	            // 順時針應遞減、逆時針應遞增
128	            if (clockwise ? !(t < cur) : !(t > cur)) allMono = false;
129	            if (!approx(((t % 360) + 360) % 360, (land * C) % 360)) allLand = false;
130	            // 模擬轉動結束後正規化（Manager 行為），下次以正規化值起算
131	            cur = NormalizeAngle(t);
132	            if (cur < 0 || cur >= 360) allBounded = false;
133	        }
134	        const dir = clockwise ? 'CW' : 'CCW';
135	        check(`BC-8 連續轉動(${dir})：每次皆同向單調`, allMono);
136	        check(`BC-8 連續轉動(${dir})：每次落點正確（含重複落點）`, allLand);
137	        check(`BC-8 連續轉動(${dir})：正規化後角度恆在 [0,360)（防漂移）`, allBounded);
138	    }
139	}
140	
141	// ─────────────────────────────────────────────
142	// BC-4：TypeToIconIndex — 已知 type 正確、未知 type 回預設
143	// ─────────────────────────────────────────────
144	{
145	    check('BC-4 已知：SymbolConvert→0', TypeToIconIndex(FeatureWheelSegmentType.SymbolConvert) === 0);
146	    check('BC-4 已知：Multiplier→1', TypeToIconIndex(FeatureWheelSegmentType.Multiplier) === 1);
147	    check('BC-4 已知：Upgrade→2', TypeToIconIndex(FeatureWheelSegmentType.Upgrade) === 2);
148	    check('BC-4 已知：GrandJP→3', TypeToIconIndex(FeatureWheelSegmentType.GrandJP) === 3);
149	    check('BC-4 已知：FreeGame→4', TypeToIconIndex(FeatureWheelSegmentType.FreeGame) === 4);
150	    check('BC-4 未知：99→預設', TypeToIconIndex(99 as FeatureWheelSegmentType) === DEFAULT_ICON_INDEX);
151	    check('BC-4 未知：-1→預設', TypeToIconIndex(-1 as FeatureWheelSegmentType) === DEFAULT_ICON_INDEX);
152	}
153	
154	// ─────────────────────────────────────────────
155	// 純 helper（支撐上述 BC 的基礎正確性）
156	// ─────────────────────────────────────────────
157	{
158	    check('helper GetDefaultSegments 回 10 格', GetDefaultSegments().length === 10);
159	    check('helper NormalizeAngle(-10)=350', approx(NormalizeAngle(-10), 350));
160	    check('helper NormalizeAngle(370)=10', approx(NormalizeAngle(370), 10));
161	    check('helper NormalizeAngle(720)=0', approx(NormalizeAngle(720), 0));
162	    check('helper IsKnownSegmentType(0)=true', IsKnownSegmentType(0) === true);
163	    check('helper IsKnownSegmentType(4)=true', IsKnownSegmentType(4) === true);
164	    check('helper IsKnownSegmentType(99)=false', IsKnownSegmentType(99) === false);
165	}
166	
167	// ─────────────────────────────────────────────
168	// 結果
169	// ─────────────────────────────────────────────
170	console.log(`\nFeatureWheelTypes 測試：${passed}/${total} 通過`);
171	if (failures.length > 0) {
172	    console.log(`失敗清單：\n  - ${failures.join('\n  - ')}`);
173	    process.exitCode = 1;
174	} else {
175	    console.log('✅ 全部通過');
176	}
