toolUseResult.originalFile:
import { _decorator, Component, error, Sprite, SpriteFrame, warn } from 'cc';
const { ccclass, property } = _decorator;

/**
 * SpriteChange
 * 用於動態切換 Sprite 元件的圖片資源
 * 可在編輯器中設定多個 SpriteFrame，透過索引切換顯示
 */
@ccclass('SpriteChange')
export class SpriteChange extends Component {

    @property({ type: [SpriteFrame], tooltip: "圖片資源陣列" })
    private m_spriteFrames: SpriteFrame[] = [];

    @property({ type: Sprite, tooltip: "目標 Sprite 元件（未設定則自動獲取當前節點的 Sprite）" })
    private m_targetSprite: Sprite = null;

    private m_currentIndex: number = -1;

    onLoad() {
        // 如果未手動設定目標 Sprite，則自動獲取當前節點的 Sprite 元件
        if (!this.m_targetSprite) {
            this.m_targetSprite = this.node.getComponent(Sprite);
            if (!this.m_targetSprite) {
                warn(`[SpriteChange] 節點 ${this.node.name} 上沒有找到 Sprite 元件`);
            }
        }
    }

    /**
     * 透過索引切換 Sprite 的圖片
     * @param index 圖片索引（從 0 開始）
     * @returns 是否切換成功
     */
    public ChangeSpriteByIndex(index: number): boolean {
        // 驗證索引範圍
        if (index < 0 || index >= this.m_spriteFrames.length) {
            error(`[SpriteChange] 索引 ${index} 超出範圍 [0, ${this.m_spriteFrames.length - 1}]`);
            return false;
        }

        // 驗證 Sprite 元件
        if (!this.m_targetSprite) {
            error(`[SpriteChange] 目標 Sprite 元件不存在`);
            return false;
        }

        // 驗證 SpriteFrame
        const spriteFrame = this.m_spriteFrames[index];
        if (!spriteFrame) {
            error(`[SpriteChange] 索引 ${index} 的 SpriteFrame 不存在`);
            return false;
        }

        // 切換圖片
        this.m_targetSprite.spriteFrame = spriteFrame;
        this.m_currentIndex = index;

        return true;
    }

    /**
     * 獲取當前顯示的圖片索引
     * @returns 當前索引，若未設定則返回 -1
     */
    public GetCurrentIndex(): number {
        return this.m_currentIndex;
    }

    /**
     * 獲取圖片資源陣列的總數量
     * @returns 圖片數量
     */
    public GetSpriteFrameCount(): number {
        return this.m_spriteFrames.length;
    }

    /**
     * 切換到下一張圖片（循環）
     * @returns 是否切換成功
     */
    public NextSprite(): boolean {
        if (this.m_spriteFrames.length === 0) {
            error(`[SpriteChange] 圖片陣列為空`);
            return false;
        }

        const nextIndex = (this.m_currentIndex + 1) % this.m_spriteFrames.length;
        return this.ChangeSpriteByIndex(nextIndex);
    }

    /**
     * 切換到上一張圖片（循環）
     * @returns 是否切換成功
     */
    public PreviousSprite(): boolean {
        if (this.m_spriteFrames.length === 0) {
            error(`[SpriteChange] 圖片陣列為空`);
            return false;
        }

        const prevIndex = this.m_currentIndex <= 0
            ? this.m_spriteFrames.length - 1
            : this.m_currentIndex - 1;
        return this.ChangeSpriteByIndex(prevIndex);
    }
}

