/**
 * @ch 依當前資料綁定各格 icon 與乘倍數值（BC-5 / BC-4 / EH-2 未知 type）
 */
private BindSegmentIcons() {
    // 迭代固定 12 格確保冪等（R-2）：二次設定變少時，超出資料的格重置為預設，不殘留舊值
    for (let i = 0; i < FEATURE_WHEEL_SEGMENT_COUNT; i++) {
        const seg = i < this.m_segments.length ? this.m_segments[i] : null;

