// ─────────────────────────────────────────────
// BC-1：ParseServerWheelData 對合法 WheelData 回 12 格，server→client type 正確映射（layer 選取）
// WheelData 第一層 0=MG 1=FG；第二層 Data = ServerWheelFeature（0 FG,1 Multi,2 Upgrade,3 Transfer,4 Grand,-1 None）
// ─────────────────────────────────────────────
{
    const raw = [
        { Data: [0, 1, 2, 3, 4, -1, 0, 1, 2, 3, 4, -1] }, // MG
        { Data: [4, 3, 1, 2, 3, -1, 0, 1, 2, 3, 4, 0] },  // FG
    ];
    const mg = ParseServerWheelData(raw, WheelDataLayer.MainGame);
    check('BC-1 MG：回傳剛好 12 格', mg.length === FEATURE_WHEEL_SEGMENT_COUNT);
    check('BC-1 MG：FG(0)→FreeGame', mg[0].type === FeatureWheelSegmentType.FreeGame);
    check('BC-1 MG：Multi(1)→Multiplier', mg[1].type === FeatureWheelSegmentType.Multiplier);
    check('BC-1 MG：Upgrade(2)→Upgrade', mg[2].type === FeatureWheelSegmentType.Upgrade);
    check('BC-1 MG：Transfer(3)→SymbolConvert', mg[3].type === FeatureWheelSegmentType.SymbolConvert);
    check('BC-1 MG：Grand(4)→GrandJP', mg[4].type === FeatureWheelSegmentType.GrandJP);
    check('BC-1 MG：None(-1)→None', mg[5].type === FeatureWheelSegmentType.None);
    check('BC-1：移除 value 欄位', (mg[1] as any).value === undefined);

    const fg = ParseServerWheelData(raw, WheelDataLayer.FreeGame);
    check('BC-1 FG：取第二層', fg[0].type === FeatureWheelSegmentType.GrandJP && fg[11].type === FeatureWheelSegmentType.FreeGame);
}

// ─────────────────────────────────────────────
// BC-2：ParseServerWheelData fallback — 整層無資料回預設 12 格
// ─────────────────────────────────────────────
{
    const def = GetDefaultSegments();
    const isDefault = (a: SegmentDescriptor[]) =>
        a.length === FEATURE_WHEEL_SEGMENT_COUNT && a.every((s, i) => s.type === def[i].type);

    check('BC-2 null → 預設 12 格', isDefault(ParseServerWheelData(null, WheelDataLayer.MainGame)));
    check('BC-2 undefined → 預設 12 格', isDefault(ParseServerWheelData(undefined, WheelDataLayer.MainGame)));
    check('BC-2 空陣列 → 預設 12 格', isDefault(ParseServerWheelData([], WheelDataLayer.MainGame)));
    check('BC-2 缺該層 → 預設 12 格', isDefault(ParseServerWheelData([{ Data: [0, 1, 2] }], WheelDataLayer.FreeGame)));
    check('BC-2 該層 Data 非陣列 → 預設 12 格', isDefault(ParseServerWheelData([{ Data: null }], WheelDataLayer.MainGame)));
    check('BC-2 該層 Data 為空 → 預設 12 格', isDefault(ParseServerWheelData([{ Data: [] }], WheelDataLayer.MainGame)));

    // 有資料但長度不足 12 → 缺格補 None（仍 12 格）
    const short = ParseServerWheelData([{ Data: [1, 1] }], WheelDataLayer.MainGame);
    check('BC-2 不足 12：補 None 且仍 12 格', short.length === FEATURE_WHEEL_SEGMENT_COUNT && short[11].type === FeatureWheelSegmentType.None);
    check('BC-2 不足 12：已提供格仍映射', short[0].type === FeatureWheelSegmentType.Multiplier);
}

