/**
 * @ch FeatureWheel 純邏輯層自動化測試（Phase 4）
 * 對象：assets/Script/FeatureWheel/FeatureWheelTypes.ts（零 cc 依賴，可在 Node 跑）
 * 執行：npx ts-node -O '{"module":"commonjs"}' --transpile-only tests/FeatureWheelTypes.test.ts
 * 涵蓋：[testable] BC-1, BC-2, BC-3, BC-4, BC-8 + 純 helper
 */

import {
    FeatureWheelSegmentType,
    SegmentDescriptor,
    ParseServerWheelData,
    WheelDataLayer,
    ComputeTargetAngle,
    TypeToIconIndex,
    NormalizeAngle,
    IsKnownSegmentType,
    GetDefaultSegments,
    FEATURE_WHEEL_SEGMENT_COUNT,
    FEATURE_WHEEL_SEGMENT_ANGLE,
    FEATURE_WHEEL_EXTRA_CIRCLES,
    DEFAULT_ICON_INDEX,
} from '../assets/Script/FeatureWheel/FeatureWheelTypes';

let total = 0;
let passed = 0;
const failures: string[] = [];

function check(name: string, cond: boolean): void {
    total++;
    if (cond) {
        passed++;
    } else {
        failures.push(name);
        console.log(`  ❌ ${name}`);
    }
}

function approx(a: number, b: number, eps = 1e-9): boolean {
    return Math.abs(a - b) < eps;
}

// ─────────────────────────────────────────────
// BC-1：ParseServerWheelData 對合法 raw 回 10 格，type 正確映射、乘倍帶 value
// ─────────────────────────────────────────────
{
    const raw = {
        Segments: [
            { Type: 0 }, { Type: 1, Value: 7 }, { Type: 2 }, { Type: 3 }, { Type: 4 },
            { Type: 0 }, { Type: 1, Value: 2 }, { Type: 2 }, { Type: 3 }, { Type: 4 },
        ],
    };
    const r = ParseServerWheelData(raw);
    check('BC-1 正常：回傳剛好 10 格', r.length === FEATURE_WHEEL_SEGMENT_COUNT);
    check('BC-1 正常：type 依序映射', r[0].type === FeatureWheelSegmentType.SymbolConvert && r[4].type === FeatureWheelSegmentType.FreeGame);
    check('BC-1 正常：乘倍格帶 value', r[1].type === FeatureWheelSegmentType.Multiplier && r[1].value === 7);
    check('BC-1 正常：非乘倍格無 value', r[0].value === undefined && r[2].value === undefined);
    // 邊界：乘倍格缺 Value → value 維持 undefined（不崩潰）
    const r2 = ParseServerWheelData({ Segments: [{ Type: 1 }, { Type: 0 }, { Type: 0 }, { Type: 0 }, { Type: 0 }, { Type: 0 }, { Type: 0 }, { Type: 0 }, { Type: 0 }, { Type: 0 }] });
    check('BC-1 邊界：乘倍格缺 Value → undefined', r2[0].type === FeatureWheelSegmentType.Multiplier && r2[0].value === undefined);
}

// ─────────────────────────────────────────────
// BC-2：ParseServerWheelData fallback — 永遠回 10 格
// ─────────────────────────────────────────────
{
    check('BC-2 null → 10 格 fallback', ParseServerWheelData(null).length === 10);
    check('BC-2 undefined → 10 格', ParseServerWheelData(undefined).length === 10);
    check('BC-2 空物件（無 Segments）→ 10 格', ParseServerWheelData({}).length === 10);
    check('BC-2 Segments 非陣列 → 10 格', ParseServerWheelData({ Segments: 'x' }).length === 10);
    check('BC-2 空 Segments 陣列 → 10 格（全預設）', ParseServerWheelData({ Segments: [] }).length === 10);

    // 違規/未知 type → 該格補預設（BC-2 保證 10 格）
    const fallback = GetDefaultSegments();
    const unknown = ParseServerWheelData({ Segments: [{ Type: 99 }] });
    check('BC-2 未知 type → 補預設且仍 10 格', unknown.length === 10 && unknown[0].type === fallback[0].type);

    // 部分缺漏 → 前格用 server、其餘補預設
    const partial = ParseServerWheelData({ Segments: [{ Type: 1, Value: 9 }] });
    check('BC-2 部分缺漏：index0 用 server', partial[0].type === FeatureWheelSegmentType.Multiplier && partial[0].value === 9);
    check('BC-2 部分缺漏：其餘補預設且 10 格', partial.length === 10 && partial[5].type === fallback[5].type);
}

// ─────────────────────────────────────────────
// BC-3：ComputeTargetAngle 單向單調 + 落點正確（順時針 / 逆時針雙向）
// 圈數期望引用常數 FEATURE_WHEEL_EXTRA_CIRCLES，避免硬編碼被調校打破
// ─────────────────────────────────────────────
{
    const C = FEATURE_WHEEL_SEGMENT_ANGLE; // 36
    const EXTRA = FEATURE_WHEEL_EXTRA_CIRCLES * 360; // 隨常數連動

    // 預設（順時針）→ 遞減；逆時針 → 遞增
    check('BC-3 CW 預設：land0 from 0 → -EXTRA', approx(ComputeTargetAngle(0, 0), -EXTRA));
    check('BC-3 CCW：land0 from 0 → +EXTRA', approx(ComputeTargetAngle(0, 0, false), EXTRA));
    check('BC-3 CCW：land3 from 0 → 3C+EXTRA', approx(ComputeTargetAngle(3, 0, false), 3 * C + EXTRA));

    for (let land = 0; land < 10; land++) {
        for (const cur of [0, 17, 100, 250, 359]) {
            // 順時針（預設）：遞減，落點對齊 base，位移幅度 ∈ [EXTRA, EXTRA+360)
            const tcw = ComputeTargetAngle(land, cur);
            check(`BC-3 CW 落點：land${land} cur${cur} 對齊 base`, approx(((tcw % 360) + 360) % 360, (land * C) % 360));
            check(`BC-3 CW 遞減：land${land} cur${cur} target<current`, tcw < cur);
            const dcw = cur - tcw;
            check(`BC-3 CW 不變號：land${land} cur${cur} |delta|∈[EXTRA,EXTRA+360)`, dcw >= EXTRA - 1e-9 && dcw < EXTRA + 360 + 1e-9);

            // 逆時針：遞增，同落點
            const tccw = ComputeTargetAngle(land, cur, false);
            check(`BC-3 CCW 落點：land${land} cur${cur} 對齊 base`, approx(((tccw % 360) + 360) % 360, (land * C) % 360));
            check(`BC-3 CCW 遞增：land${land} cur${cur} target>current`, tccw > cur);
            const dccw = tccw - cur;
            check(`BC-3 CCW 不變號：land${land} cur${cur} delta∈[EXTRA,EXTRA+360)`, dccw >= EXTRA - 1e-9 && dccw < EXTRA + 360 + 1e-9);
        }
    }
}

// ─────────────────────────────────────────────
// BC-8：連續多次轉動 — 每次同向單調、落點正確、正規化防漂移（雙向）
// ─────────────────────────────────────────────
{
    const C = FEATURE_WHEEL_SEGMENT_ANGLE;
    const lands = [3, 7, 0, 9, 5, 5]; // 含重複落點（5→5）

    for (const clockwise of [true, false]) {
        let cur = 0;
        let allMono = true;
        let allLand = true;
        let allBounded = true;
        for (const land of lands) {
            const t = ComputeTargetAngle(land, cur, clockwise);
            // 順時針應遞減、逆時針應遞增
            if (clockwise ? !(t < cur) : !(t > cur)) allMono = false;
            if (!approx(((t % 360) + 360) % 360, (land * C) % 360)) allLand = false;
            // 模擬轉動結束後正規化（Manager 行為），下次以正規化值起算
            cur = NormalizeAngle(t);
            if (cur < 0 || cur >= 360) allBounded = false;
        }
        const dir = clockwise ? 'CW' : 'CCW';
        check(`BC-8 連續轉動(${dir})：每次皆同向單調`, allMono);
        check(`BC-8 連續轉動(${dir})：每次落點正確（含重複落點）`, allLand);
        check(`BC-8 連續轉動(${dir})：正規化後角度恆在 [0,360)（防漂移）`, allBounded);
    }
}

// ─────────────────────────────────────────────
// BC-4：TypeToIconIndex — 已知 type 正確、未知 type 回預設
// ─────────────────────────────────────────────
{
    check('BC-4 已知：SymbolConvert→0', TypeToIconIndex(FeatureWheelSegmentType.SymbolConvert) === 0);
    check('BC-4 已知：Multiplier→1', TypeToIconIndex(FeatureWheelSegmentType.Multiplier) === 1);
    check('BC-4 已知：Upgrade→2', TypeToIconIndex(FeatureWheelSegmentType.Upgrade) === 2);
    check('BC-4 已知：GrandJP→3', TypeToIconIndex(FeatureWheelSegmentType.GrandJP) === 3);
    check('BC-4 已知：FreeGame→4', TypeToIconIndex(FeatureWheelSegmentType.FreeGame) === 4);
    check('BC-4 未知：99→預設', TypeToIconIndex(99 as FeatureWheelSegmentType) === DEFAULT_ICON_INDEX);
    check('BC-4 未知：-1→預設', TypeToIconIndex(-1 as FeatureWheelSegmentType) === DEFAULT_ICON_INDEX);
}

// ─────────────────────────────────────────────
// 純 helper（支撐上述 BC 的基礎正確性）
// ─────────────────────────────────────────────
{
    check('helper GetDefaultSegments 回 10 格', GetDefaultSegments().length === 10);
    check('helper NormalizeAngle(-10)=350', approx(NormalizeAngle(-10), 350));
    check('helper NormalizeAngle(370)=10', approx(NormalizeAngle(370), 10));
    check('helper NormalizeAngle(720)=0', approx(NormalizeAngle(720), 0));
    check('helper IsKnownSegmentType(0)=true', IsKnownSegmentType(0) === true);
    check('helper IsKnownSegmentType(4)=true', IsKnownSegmentType(4) === true);
    check('helper IsKnownSegmentType(99)=false', IsKnownSegmentType(99) === false);
}

// ─────────────────────────────────────────────
// 結果
// ─────────────────────────────────────────────
console.log(`\nFeatureWheelTypes 測試：${passed}/${total} 通過`);
if (failures.length > 0) {
    console.log(`失敗清單：\n  - ${failures.join('\n  - ')}`);
    process.exitCode = 1;
} else {
    console.log('✅ 全部通過');
}

