    Transfer = 3,
    /**@ch FG 專用：Grand JP*/
    Grand = 4,
}

/** @ch WheelData 第一層索引語意（0:主遊戲 1:免費遊戲） */
export enum WheelDataLayer {
    MainGame = 0,
    FreeGame = 1,
}

/**
 * @ch server 功能類型 → client segment 類型（兩邊編號不同，顯式映射，禁止直接 cast）
 * @param raw server 端 int（ServerWheelFeature）
 * @returns client FeatureWheelSegmentType；未觸發 / 未知值 → None（不顯示）
 */
export function MapServerFeatureToSegmentType(raw: number): FeatureWheelSegmentType {
    switch (raw) {
        case ServerWheelFeature.FreeGame:   return FeatureWheelSegmentType.FreeGame;
        case ServerWheelFeature.Multiplier: return FeatureWheelSegmentType.Multiplier;
        case ServerWheelFeature.Upgrade:    return FeatureWheelSegmentType.Upgrade;
        case ServerWheelFeature.Transfer:   return FeatureWheelSegmentType.SymbolConvert;
        case ServerWheelFeature.Grand:      return FeatureWheelSegmentType.GrandJP;
        default:                            return FeatureWheelSegmentType.None;
    }
}

/**
 * @ch server 介面隔離 adapter（BC-1 / BC-2）
 * WheelData 結構：IIntAry[]，第一層 = WheelDataLayer（0:MG 1:FG），第二層 Data = 各格的 ServerWheelFeature
 * 整層無資料（缺層 / Data 非陣列 / Data 為空）→ 回預設 12 格；有資料 → 逐格映射，缺格/未知 → None（不顯示）
 * @param raw server 原始 WheelData（protocol.ar2es2Proto.IIntAry[]；用結構化簽章避免依賴 proto 型別，保住純邏輯層）
 * @param layer 取主遊戲或免費遊戲那一層
 * @returns 剛好 12 格的 SegmentDescriptor 陣列
 */
export function ParseServerWheelData(
    raw: ReadonlyArray<{ Data?: number[] | null }> | null | undefined,
    layer: WheelDataLayer,
): SegmentDescriptor[] {
    const fallback = GetDefaultSegments();

    // 整層無資料 → 全 fallback（BC-2 / 用戶確認：沒有任何資料時用原本預設）
    const layerData = Array.isArray(raw) ? raw[layer]?.Data : null;
    if (!Array.isArray(layerData) || layerData.length === 0) {
        return fallback;
    }

    // 有資料：固定 12 格逐格映射（缺格 → None）
    const result: SegmentDescriptor[] = [];
    for (let i = 0; i < FEATURE_WHEEL_SEGMENT_COUNT; i++) {
        const rawType = typeof layerData[i] === 'number' ? layerData[i] : ServerWheelFeature.None;
        result.push({ type: MapServerFeatureToSegmentType(rawType) });
    }
    return result;
}

/**
 * @ch 計算單調的絕對目標角（BC-3）
 * 順時針（預設）→ z 角遞減；逆時針 → z 角遞增。兩方向落點 orientation 同為 baseAngle。
 * Cocos +z 為逆時針，故順時針取負向 delta，再疊固定額外圈數，全程不變號（避免視覺反向）。
 * 不沿用 MultiplierManager 的 angleDiff = target - start（會中途反向）。
 * @param landIndex 落點格索引 (0~11)
 * @param currentAngle 輪盤當前角度（度，取自節點 eulerAngles.z）
 * @param clockwise 是否順時針（預設 true）
 * @returns 絕對目標角（度）；clockwise=true 時 < currentAngle，false 時 > currentAngle
 */
export function ComputeTargetAngle(landIndex: number, currentAngle: number, clockwise: boolean = true): number {
    const baseAngle = landIndex * FEATURE_WHEEL_SEGMENT_ANGLE;
    const extra = FEATURE_WHEEL_EXTRA_CIRCLES * 360;
    if (clockwise) {
        // 順時針：z 角遞減。backwardDelta 取正向（0~360）使落點對齊 base，再多轉 extra 整圈
        const backwardDelta = NormalizeAngle(currentAngle - baseAngle);
        return currentAngle - backwardDelta - extra;
    }
    // 逆時針：z 角遞增。forwardDelta 取正向（0~360），等同 NormalizeAngle(baseAngle - currentAngle)
    const forwardDelta = NormalizeAngle(baseAngle - currentAngle);
    return currentAngle + forwardDelta + extra;
}

/**
 * @ch 正規化角度到 0~360（每次轉動結束後呼叫，防 BC-8 連續轉動的累積漂移 · DR-9）
 * @param angle 任意角度（度）
 */
export function NormalizeAngle(angle: number): number {
    return ((angle % 360) + 360) % 360;
}

